import React, { useState } from 'react';
import axios from 'axios';
import { useNavigate } from 'react-router-dom';

function Signup() {
  const [formData, setFormData] = useState({ username: '', email: '', password: '' });
  const navigate = useNavigate();

  const handleSignup = async (e) => {
    e.preventDefault();
    try {
      // Backend expects: username, email, password as query params
      await axios.post(`http://127.0.0.1:8000/api/register?username=${formData.username}&email=${formData.email}&password=${formData.password}`);
      alert("Registration Successful! Ab login karein.");
      navigate('/login');
    } catch (err) {
      alert("Error: " + (err.response?.data?.detail || "Registration failed"));
    }
  };

  return (
    <div style={{ padding: '50px', textAlign: 'center' }}>
      <h2>Naya Account Banayein</h2>
      <form onSubmit={handleSignup}>
        <input type="text" placeholder="Username" onChange={(e) => setFormData({...formData, username: e.target.value})} required style={{padding: '8px', margin: '5px'}} /><br/>
        <input type="email" placeholder="Email" onChange={(e) => setFormData({...formData, email: e.target.value})} required style={{padding: '8px', margin: '5px'}} /><br/>
        <input type="password" placeholder="Password" onChange={(e) => setFormData({...formData, password: e.target.value})} required style={{padding: '8px', margin: '5px'}} /><br/>
        <button type="submit" style={{ backgroundColor: '#3498db', color: 'white', padding: '10px 20px', border: 'none', cursor: 'pointer' }}>Register</button>
      </form>
    </div>
  );
}
export default Signup;
